#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
typedef long long ll;
const int N=4e7+10,MM=1e5+10,MMM=(1<<30)-1,S=(1<<24)-1;
int n;ll s[N];int q[N],h,t,g[N];__int128 dp[1<<24];
inline void print(__int128 p){if(p>9)print(p/10);putchar(p%10+'0');}
int main()
{
	n=read();dp[0]=0;g[0]=0;
	if(read()==0)rep(1,n,i)s[i]=s[i-1]+read();
	else
	{
		int x=read(),y=read(),z=read();s[1]=read();s[2]=read();
		rep(3,n,i)s[i]=(1ll*x*s[i-1]+1ll*y*s[i-2]+z)&MMM;int m=read(),lst=0;
		rep(1,m,i){int p=read(),l=read(),r=read();rep(lst+1,p,j)s[j]=s[j-1]+(s[j]%(r-l+1))+l;lst=p;}
	}
	q[h=t=0]=0;rep(1,n,i)
	{
		while(h<t&&s[i]>=2*s[q[h+1]]-s[g[q[h+1]]])++h;
		dp[i&S]=dp[q[h]&S]+(__int128)(s[i]-s[q[h]])*(s[i]-s[q[h]]);g[i]=q[h];
		while(h<=t&&2*s[q[t]]-s[g[q[t]]]>2*s[i]-s[g[i]])--t;q[++t]=i;
	}
	print(dp[n&S]);return 0;
}
